import{_ as a,o as t,c as r,ae as o}from"./chunks/framework.Czhw_PXq.js";const u=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1776574990000}'),n={name:"guide/index.md"};function i(s,e,l,c,d,h){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>EasyYapi is an IntelliJ IDEA plugin that generates API documentation based on <a href="./docs#javadoc">Javadoc</a>, <a href="./docs#kdoc">KDoc</a>, and <a href="./docs#scaladoc">ScalaDoc</a>.</p><p>You can get fairly complete API documentation while keeping your code zero-intrusive, but special requirements still need some special comments/annotations to cooperate. On the other hand, you can flexibly use <a href="/settings/">configuration rules</a> to adapt to your project characteristics to reduce code intrusion.</p><p>::: note Since the <code>openapi</code> provided by the Scala plugin changes too frequently, Scala is no longer a default support option. Developers who need to use it in Scala projects can obtain the Scala-supported plugin package from <a href="https://github.com/tangcent/easy-yapi/releases" target="_blank" rel="noreferrer">easy-yapi/releases</a>. :::</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><ul><li><a href="./use">Export API documentation</a></li><li><a href="./call">Call API directly in IDEA</a></li></ul><h2 id="supported-items" tabindex="-1">Supported Items <a class="header-anchor" href="#supported-items" aria-label="Permalink to &quot;Supported Items&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Default Support</th><th>Additional Support</th></tr></thead><tbody><tr><td>Language</td><td>Java, Kotlin</td><td>Scala</td></tr><tr><td>Web Framework</td><td><a href="https://spring.io/" target="_blank" rel="noreferrer">Spring</a>, <a href="https://docs.spring.io/spring-framework/reference/web/webflux.html" target="_blank" rel="noreferrer">Spring WebFlux</a>, <a href="https://spring.io/projects/spring-cloud-openfeign" target="_blank" rel="noreferrer">Feign</a>, <a href="https://www.oracle.com/technical-resources/articles/java/jax-rs.html" target="_blank" rel="noreferrer">JAX-RS</a> (<a href="https://quarkus.io/" target="_blank" rel="noreferrer">Quarkus</a> / <a href="https://eclipse-ee4j.github.io/jersey/" target="_blank" rel="noreferrer">Jersey</a>), <a href="https://grpc.io/" target="_blank" rel="noreferrer">gRPC</a></td><td><a href="https://dubbo.apache.org" target="_blank" rel="noreferrer">Dubbo</a></td></tr><tr><td>Export Channels</td><td><a href="./export2postman">Postman</a>, <a href="./export2yapi">YApi</a>, <a href="./export2markdown">Markdown</a></td><td>-</td></tr><tr><td>Common Frameworks</td><td>javax.validation, Jakarta Validation, Jackson, Gson</td><td><a href="https://swagger.io/" target="_blank" rel="noreferrer">Swagger</a>, Fastjson</td></tr><tr><td>Features</td><td><a href="./call">API Call</a>, <a href="./call#api-dashboard">API Dashboard</a>, <a href="./script-executor">Script Executor</a></td><td>Spring Actuator</td></tr></tbody></table><h2 id="community" tabindex="-1">Community <a class="header-anchor" href="#community" aria-label="Permalink to &quot;Community&quot;">​</a></h2><ul><li>Help maintain documentation: <a href="https://github.com/easyyapi/easyyapi.github.io/tree/dev" target="_blank" rel="noreferrer">easyyapi.com</a> — Please submit PRs to the dev branch</li><li>Discuss <a href="https://github.com/tangcent/easy-yapi/issues?q=label%3Aenhancement" target="_blank" rel="noreferrer">new features</a> or submit <a href="https://github.com/tangcent/easy-yapi/issues?q=label%3Abug" target="_blank" rel="noreferrer">bugs</a>: <a href="https://github.com/tangcent/easy-yapi/issues" target="_blank" rel="noreferrer">Issues</a></li><li>Develop <a href="https://github.com/tangcent/easy-yapi/pulls?q=+label%3Aenhancement" target="_blank" rel="noreferrer">new features</a> or fix <a href="https://github.com/tangcent/easy-yapi/pulls?q=+label%3Abug" target="_blank" rel="noreferrer">bugs</a>: <a href="https://github.com/tangcent/easy-yapi/pulls" target="_blank" rel="noreferrer">Pull Requests</a></li><li>Maintain recommended configuration: <a href="https://github.com/tangcent/easy-yapi/blob/master/idea-plugin/src/main/resources/.recommend.easy.api.config" target="_blank" rel="noreferrer">.recommend.easy.api.config</a></li><li>Enrich Demo: <a href="https://github.com/Earth-1610/web-demo" target="_blank" rel="noreferrer">web-demo</a></li></ul><h2 id="contributors" tabindex="-1">Contributors <a class="header-anchor" href="#contributors" aria-label="Permalink to &quot;Contributors&quot;">​</a></h2><a href="https://github.com/tangcent/easy-yapi/graphs/contributors"><img src="https://contrib.rocks/image?repo=tangcent/easy-yapi"></a>',12)])])}const g=a(n,[["render",i]]);export{u as __pageData,g as default};
